import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [tab, setTab] = useState('users');
  const [themeTrigger, setThemeTrigger] = useState(false);

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
    API.get('/admin/comments').then(res => setComments(res.data));
  }, []);

  useEffect(() => {
    const handleThemeChange = () => setThemeTrigger(prev => !prev);
    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  const removePost = async (id) => {
    if (!window.confirm("Permanently delete this post? This cannot be undone.")) return;
    try {
      await API.delete(`/posts/${id}`); 
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      alert("Error deleting post.");
    }
  };

  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(comments.filter(c => c._id !== id));
  };

  const viewPost = (postId) => {
    navigate(`/posts/${postId}`);
  };

  const isDark = document.body.classList.contains('dark-mode');

  const colors = {
    lightPink: '#FCE4EC',
    mainPink: '#F8BBD0',
    darkGreen: '#1B5E20',
    softGreen: '#E8F5E9',
    white: '#FFFFFF',
    textDark: '#0A2610'
  };

  const styles = {
    page: {
      backgroundColor: isDark ? '#1a0505' : colors.lightPink,
      minHeight: '100vh',
      padding: '40px 20px',
      fontFamily: '"Segoe UI", Tahoma, sans-serif',
      color: isDark ? '#fce4ec' : colors.textDark,
    },
    container: {
      maxWidth: '1200px',
      margin: '0 auto',
    },
    heading: {
      fontSize: '36px',
      textAlign: 'center',
      marginBottom: '40px',
      fontWeight: '900',
      color: colors.darkGreen,
      textTransform: 'uppercase',
      letterSpacing: '2px'
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '15px',
      marginBottom: '40px',
    },
    tabButton: {
      padding: '12px 30px',
      borderRadius: '50px',
      border: `2px solid ${colors.darkGreen}`,
      cursor: 'pointer',
      fontWeight: 'bold',
      backgroundColor: 'transparent',
      color: colors.darkGreen,
      transition: 'all 0.3s ease',
    },
    activeTab: {
      backgroundColor: colors.darkGreen,
      color: colors.lightPink,
    },
    grid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
      gap: '20px',
    },
    card: {
      backgroundColor: isDark ? '#2e0a0a' : colors.white,
      padding: '25px',
      borderRadius: '20px',
      boxShadow: '0 8px 20px rgba(0,0,0,0.05)',
      border: `1px solid ${colors.mainPink}`,
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'space-between',
    },
    cardTitle: {
      fontSize: '18px',
      fontWeight: 'bold',
      color: colors.darkGreen,
      marginBottom: '10px',
    },
    cardSub: {
      fontSize: '14px',
      color: '#666',
      marginBottom: '20px',
    },
    actionRow: {
      display: 'flex',
      gap: '10px',
      marginTop: 'auto',
    },
    btnView: {
      flex: 1,
      padding: '10px',
      borderRadius: '12px',
      border: 'none',
      backgroundColor: colors.darkGreen,
      color: colors.white,
      cursor: 'pointer',
      fontWeight: '600',
      textAlign: 'center',
      transition: 'transform 0.2s',
    },
    btnDelete: {
      flex: 1,
      padding: '10px',
      borderRadius: '12px',
      border: `2px solid #ff4d6d`,
      backgroundColor: 'transparent',
      color: '#ff4d6d',
      cursor: 'pointer',
      fontWeight: '600',
      textAlign: 'center',
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Admin Dashboard</h2>

        <div style={styles.tabs}>
          {['users', 'posts', 'comments'].map((t) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              style={{ ...styles.tabButton, ...(tab === t ? styles.activeTab : {}) }}
            >
              {t.toUpperCase()}
            </button>
          ))}
        </div>

        <div style={styles.grid}>
          {/* USERS RENDER */}
          {tab === 'users' && users.map(u => (
            <div key={u._id} style={styles.card}>
              <div>
                <div style={styles.cardTitle}>{u.name}</div>
                <div style={styles.cardSub}>{u.email}</div>
                <div style={{...styles.cardSub, color: u.status === 'active' ? 'green' : 'red'}}>
                   Status: {u.status}
                </div>
              </div>
              <button style={styles.btnView} onClick={() => toggleStatus(u._id)}>
                {u.status === 'active' ? 'Ban User' : 'Unban User'}
              </button>
            </div>
          ))}

          {/* POSTS RENDER */}
          {tab === 'posts' && posts.map(p => (
            <div key={p._id} style={styles.card}>
              <div>
                <div style={styles.cardTitle}>{p.title}</div>
                <div style={styles.cardSub}>By: {p.author?.name || 'Unknown'}</div>
              </div>
              <div style={styles.actionRow}>
                <button style={styles.btnView} onClick={() => viewPost(p._id)}>
                  👁 View
                </button>
                <button style={styles.btnDelete} onClick={() => removePost(p._id)}>
                  🗑 Delete
                </button>
              </div>
            </div>
          ))}

          {/* COMMENTS RENDER */}
          {tab === 'comments' && comments.map(c => (
            <div key={c._id} style={styles.card}>
              <div>
                <div style={styles.cardTitle}>{c.author?.name}</div>
                <p style={{fontSize: '14px', fontStyle: 'italic'}}>"{c.body}"</p>
              </div>
              <button style={styles.btnDelete} onClick={() => deleteComment(c._id)}>
                Remove Comment
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default AdminPage;
